import React from 'react';

interface Order {
  id: string;
  customerName: string;
  totalAmount: number;
  status: string;
  date: string;
}

interface OrderListProps {
  orders: Order[];
  onSelectOrder: (id: string) => void;
}

const OrderList: React.FC<OrderListProps> = ({ orders, onSelectOrder }) => {
  return (
    <div className="bg-gray-900 p-6 rounded-xl shadow-md">
      <h2 className="text-2xl font-semibold text-white mb-4">Orders</h2>
      <div className="overflow-x-auto">
        <table className="min-w-full bg-gray-800 rounded-xl">
          <thead>
            <tr>
              <th className="text-left text-gray-400 px-4 py-2">Order ID</th>
              <th className="text-left text-gray-400 px-4 py-2">Customer</th>
              <th className="text-left text-gray-400 px-4 py-2">Total</th>
              <th className="text-left text-gray-400 px-4 py-2">Status</th>
              <th className="text-left text-gray-400 px-4 py-2">Date</th>
            </tr>
          </thead>
          <tbody>
            {orders.length === 0 ? (
              <tr>
                <td colSpan={5} className="text-center text-gray-500 py-4">
                  No orders found.
                </td>
              </tr>
            ) : (
              orders.map(order => (
                <tr
                  key={order.id}
                  onClick={() => onSelectOrder(order.id)}
                  className="hover:bg-gray-700 cursor-pointer transition-colors"
                >
                  <td className="text-white px-4 py-2">{order.id}</td>
                  <td className="text-white px-4 py-2">{order.customerName}</td>
                  <td className="text-white px-4 py-2">${order.totalAmount.toFixed(2)}</td>
                  <td className="text-white px-4 py-2">{order.status}</td>
                  <td className="text-white px-4 py-2">{order.date}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default OrderList;
